package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
    }

    @Test
    void testPrintCreatesCSVPrinter() throws IOException {
        // Instead of mocking CSVFormat (final class), call real method on CSVFormat.DEFAULT
        CSVPrinter printer = csvFormat.print(mockFile, charset);

        assertNotNull(printer);
        // Since CSVPrinter is created by the real method, verify it's instance of CSVPrinter
        assertEquals(CSVPrinter.class, printer.getClass());
    }

    @Test
    void testPrintThrowsIOException() {
        // Passing null charset should throw NullPointerException as per current implementation
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
